<js>
//只保留书名长度最短的图书。
var len = (o) => String(o.text()).length;
var list = result.toArray();
var min = Math.min.apply(null, list.map(e => len(e)));
result = list.filter(e => len(e) === min).map(v => java.ajax('https://www.guishuji.com'+v.attr('href')));
</js>
